        // Add a flag to control static vs dynamic tool map
        public static bool UseDynamicToolMap => Environment.GetEnvironmentVariable("MCP_DYNAMIC_TOOLMAP") == "true";

        // Method to load tool map dynamically from OpenAPI spec (if enabled)
        public static Dictionary<string, ToolMetadata> GetToolMappings()
        {
            if (!UseDynamicToolMap)
                return ToolMappings;

            // Try to load and parse OpenAPI spec from local file (cipp-api-openapi.json)
            var openApiPath = Path.Combine(AppContext.BaseDirectory, "cipp-api-openapi.json");
            if (!File.Exists(openApiPath))
                return ToolMappings; // fallback

            var json = File.ReadAllText(openApiPath);
            var doc = JsonDocument.Parse(json);
            var map = new Dictionary<string, ToolMetadata>();
            if (doc.RootElement.TryGetProperty("paths", out var paths))
            {
                foreach (var pathProp in paths.EnumerateObject())
                {
                    var endpoint = pathProp.Name;
                    foreach (var methodProp in pathProp.Value.EnumerateObject())
                    {
                        var method = methodProp.Name.ToUpperInvariant();
                        var enabled = method == "GET"; // Only enable GET by default
                        var summary = methodProp.Value.TryGetProperty("summary", out var s) ? s.GetString() : "";
                        var desc = methodProp.Value.TryGetProperty("description", out var d) ? d.GetString() : summary;
                        var parameters = new List<ParameterRequirement>();
                        if (methodProp.Value.TryGetProperty("parameters", out var paramArr))
                        {
                            foreach (var param in paramArr.EnumerateArray())
                            {
                                var pname = param.GetProperty("name").GetString();
                                var ptype = param.TryGetProperty("schema", out var sch) && sch.TryGetProperty("type", out var t) ? t.GetString() : "string";
                                var preq = param.TryGetProperty("required", out var rq) && rq.GetBoolean();
                                var pdesc = param.TryGetProperty("description", out var pd) ? pd.GetString() : "";
                                parameters.Add(new ParameterRequirement(pname, ptype, preq, pdesc));
                            }
                        }
                        // Tool name: try to use tag or summary, fallback to endpoint
                        var toolName = methodProp.Value.TryGetProperty("tags", out var tags) && tags.GetArrayLength() > 0 ? tags[0].GetString() : endpoint.Trim('/');
                        map[toolName] = new ToolMetadata(
                            endpoint,
                            new HttpMethod(method),
                            "CIPP/Other",
                            enabled,
                            desc ?? "",
                            parameters
                        );
                    }
                }
            }
            return map;
        }
    }
